      device_id: 'mgr-device-001',
      shop_id: mainShop._id,
      assigned_shop_ids: [mainShop._id, eastShop._id],
      must_change_password: true,
    },
    {
      name: 'Carol Sub-Manager',
      email: 'submanager@org.com',
      phone_code: '+44',
      phone_num: '7000000003',
