      role_id: staffRole._id,
      device_id: 'staff-device-001',
      shop_id: mainShop._id,
      assigned_shop_ids: [mainShop._id],
      must_change_password: true,
    },
  ];

  // Create one by one to trigger the pre-save bcrypt hook on each
  const users = [];
  for (const u of usersRaw) {
    const created = await User.create(u);
    users.push(created);
  }

  const rootUser   = users[0];
  const staffUser  = users[4];
  console.log(`✅ ${users.length} users created`);

  // ─── 4. Rotas ─────────────────────────────────────────
  const today = new Date();
  const tomorrow = new Date(today);
  tomorrow.setDate(today.getDate() + 1);

  await Rota.insertMany([
    {
      user_id: staffUser._id,
      shop_id: mainShop._id,
      shift_date: today,
      start_time: '09:00',
    },
    {
      user_id: staffUser._id,
      shop_id: eastShop._id,
      shift_date: tomorrow,
      start_time: '10:00',
    },
  ]);
  console.log('✅ 2 rotas created');

  // ─── 5. Inventory Items ───────────────────────────────
  await InventoryItem.insertMany([
    {
      shop_id: mainShop._id,
      item_name: 'Cash Register',
      purchase_date: new Date('2024-01-15'),
      expiry_date: null,
      status: 'Good',
    },
    {
      shop_id: mainShop._id,
      item_name: 'Barcode Scanner',
      purchase_date: new Date('2023-06-10'),
      expiry_date: null,
      status: 'Good',
    },
    {
      shop_id: eastShop._id,
      item_name: 'Display Monitor',
      purchase_date: new Date('2022-11-20'),
      expiry_date: null,
      status: 'Good',
    },
    {
      shop_id: eastShop._id,
      item_name: 'Fire Extinguisher',
      purchase_date: new Date('2023-03-01'),
      expiry_date: new Date('2026-03-01'),
      status: 'Good',
    },
  ]);
  console.log('✅ 4 inventory items created');

  // ─── Summary ──────────────────────────────────────────
  console.log('\n Seed complete! Default credentials:\n');
  console.log('  Role       | Email                  | Password');
  console.log('  -----------|------------------------|-------------');
  console.log('  Root       | root@org.com           | Root@1234');
  console.log('  Admin      | admin@org.com          | Admin@1234');
  console.log('  Manager    | manager@org.com        | Manager@1234');
  console.log('  Sub-Mgr    | submanager@org.com     | SubMgr@1234');
  console.log('  Staff      | staff@org.com          | Staff@1234');
  console.log('\n⚠️  Change all passwords after first login!\n');

  await mongoose.disconnect();
  process.exit(0);
};

seed().catch((err) => {
  console.error('❌ Seed failed:', err.message);
  process.exit(1);
});

const swaggerJsdoc = require('swagger-jsdoc');

const options = {
  definition: {
    openapi: '3.0.0',
    info: {
      title: 'Staff & Inventory Management API',
      version: '1.0.0',
      description:
        'REST API for managing staff rotas, attendance (GPS + Biometric punch-in), and inventory with role-based access control.',
      contact: {
        name: 'API Support',
        email: 'root@org.com',
      },
    },
    servers: [
      { url: 'http://localhost:3000', description: 'Local development' },
    ],
    components: {
      securitySchemes: {
        BearerAuth: {
          type: 'http',
          scheme: 'bearer',
          bearerFormat: 'JWT',
          description: 'Enter your JWT token (from POST /api/auth/login)',
        },
      },
      schemas: {
        // ── Auth ──
        LoginRequest: {
          type: 'object',
          required: ['email', 'password'],
          properties: {
            email: { type: 'string', example: 'root@org.com' },
            password: { type: 'string', example: 'Root@1234' },
          },
        },
        LoginResponse: {
          type: 'object',
          properties: {
            success: { type: 'boolean' },
            token: { type: 'string' },
            must_change_password: { type: 'boolean' },
            user: { $ref: '#/components/schemas/UserPublic' },
          },
        },

        // ── Role ──
        Role: {
          type: 'object',
          properties: {
            _id: { type: 'string' },
            role_name: { type: 'string', example: 'Manager' },
            permissions: {
              type: 'object',
              example: {
                can_create_users: false,
                can_view_all_staff: true,
                can_manage_rotas: true,
                can_manual_punch: true,
                can_manage_inventory: true,
                can_manage_shops: false,
                can_manage_roles: false,
              },
            },
          },
        },

        // ── Shop ──
        Shop: {
          type: 'object',
          properties: {
            _id: { type: 'string' },
            name: { type: 'string', example: 'Main Branch' },
            latitude: { type: 'number', example: 51.5074 },
            longitude: { type: 'number', example: -0.1278 },
            geofence_radius_m: { type: 'number', example: 150 },
          },
        },
        ShopInput: {
          type: 'object',
          required: ['name', 'latitude', 'longitude'],
          properties: {
            name: { type: 'string' },
            latitude: { type: 'number' },
            longitude: { type: 'number' },
            geofence_radius_m: { type: 'number', default: 100 },
          },
        },

        // ── User ──
        UserPublic: {
          type: 'object',
          properties: {
            _id: { type: 'string' },
            name: { type: 'string' },
            email: { type: 'string' },
            phone_code: { type: 'string' },
            phone_num: { type: 'string' },
            device_id: { type: 'string' },
            role_id: { $ref: '#/components/schemas/Role' },
            shop_id: { $ref: '#/components/schemas/Shop' },
            is_active: { type: 'boolean' },
            must_change_password: { type: 'boolean' },
          },
        },
        CreateUserRequest: {
          type: 'object',
          required: ['name', 'email', 'password', 'role_id'],
          properties: {
            name: { type: 'string', example: 'Jane Doe' },
            email: { type: 'string', example: 'jane@org.com' },
            password: { type: 'string', example: 'Temp@1234' },
            phone_code: { type: 'string', example: '+44' },
            phone_num: { type: 'string', example: '7000000099' },
            role_id: { type: 'string' },
            device_id: { type: 'string' },
            shop_id: { type: 'string' },
          },
        },
        PasswordUpdateRequest: {
          type: 'object',
          required: ['currentPassword', 'newPassword'],
          properties: {
            currentPassword: { type: 'string' },
            newPassword: { type: 'string', minLength: 8 },
          },
        },

        // ── Rota ──
        Rota: {
          type: 'object',
          properties: {
            _id: { type: 'string' },
            user_id: { $ref: '#/components/schemas/UserPublic' },
            shop_id: { $ref: '#/components/schemas/Shop' },
            shift_date: { type: 'string', format: 'date' },
            start_time: { type: 'string', example: '09:00' },
            end_time: { type: 'string', example: '17:00' },
            note: { type: 'string' },
          },
        },
        RotaInput: {
          type: 'object',
          required: ['user_id', 'shop_id', 'shift_date', 'start_time'],
          properties: {
            user_id: { type: 'string' },
            shop_id: { type: 'string' },
            shift_date: { type: 'string', format: 'date' },
            start_time: { type: 'string', example: '09:00' },
            end_time: { type: 'string', example: '17:00' },
            note: { type: 'string' },
          },
        },
        BulkRotaRequest: {
          type: 'object',
          required: ['shop_id', 'week_start', 'days', 'assignments'],
          properties: {
            shop_id: { type: 'string' },
            week_start: { type: 'string', format: 'date', example: '2026-03-16', description: 'Any date — snapped to that ISO week Monday' },
            days: {
              type: 'array',
              items: { type: 'integer', minimum: 0, maximum: 6 },
              description: '0=Mon, 1=Tue, 2=Wed, 3=Thu, 4=Fri, 5=Sat, 6=Sun',
              example: [0, 1, 2, 3, 4],
            },
            assignments: {
              type: 'array',
              description: 'Each assignment is applied to every selected day. Multiple entries for same user = split shifts.',
              items: {
                type: 'object',
                required: ['user_id', 'start_time'],
                properties: {
                  user_id: { type: 'string' },
                  start_time: { type: 'string', example: '09:00' },
                  end_time: { type: 'string', example: '17:00' },
                  note: { type: 'string', example: 'Opening shift' },
                },
              },
            },
            replace_existing: {
              type: 'boolean',
              default: false,
              description: 'If true: delete the specified users\' full week first, then re-insert. Use to re-publish a week.',
            },
          },
        },
        BulkRotaResponse: {
          type: 'object',
          properties: {
            success: { type: 'boolean' },
            created: { type: 'integer', description: 'Number of new rota records inserted' },
            skipped: { type: 'integer', description: 'Number of entries skipped due to conflicts' },
            conflicts: {
              type: 'array',
              items: {
                type: 'object',
                properties: {
                  user_id: { type: 'string' },
                  date: { type: 'string' },
                  start_time: { type: 'string' },
                  reason: { type: 'string' },
                },
              },
            },
            message: { type: 'string' },
          },
        },
        WeekViewResponse: {
          type: 'object',
          properties: {
            success: { type: 'boolean' },
            week_start: { type: 'string' },
            week_end: { type: 'string' },
            shop_id: { type: 'string' },
            days: {
              type: 'object',
              description: 'Keys are day labels (e.g. "Mon 16 Mar"), values are arrays of Rota records',
              additionalProperties: {
                type: 'array',
                items: { $ref: '#/components/schemas/Rota' },
              },
            },
          },
        },
        DashboardResponse: {
          type: 'object',
          properties: {
            success: { type: 'boolean' },
            week_start: { type: 'string' },
            week_end: { type: 'string' },
            total_shifts: { type: 'integer' },
            by_shop: {
              type: 'array',
              items: {
                type: 'object',
                properties: {
                  shop: { $ref: '#/components/schemas/Shop' },
                  days: {
                    type: 'object',
                    description: 'Keys: "Mon 16 Mar" etc. Values: shift entries for that day',
                    additionalProperties: { type: 'array', items: { type: 'object' } },
                  },
                },
              },
            },
            by_employee: {
              type: 'array',
              items: {
                type: 'object',
                properties: {
                  user: { $ref: '#/components/schemas/UserPublic' },
                  shifts: {
                    type: 'array',
                    items: {
                      type: 'object',
