// @route  POST /api/users
// @access Admin only (requires can_create_users permission)
const createUser = async (req, res) => {
  try {
    const {
      name,
      email,
      phone_code,
      phone_num,
      password,
      role_id,
      device_id,
      shop_id,
      assigned_shop_ids,
    } = req.body;

    const existing = await User.findOne({ email });
    if (existing) {
      return res.status(400).json({ success: false, message: 'Email already in use' });
    }

    const normalizedAssignedShopIds = normalizeAssignedShopIds(assigned_shop_ids, shop_id);
    const primaryShopId = shop_id || normalizedAssignedShopIds[0] || null;

    if (!isRequestedShopSetAllowed(req.shopScope, normalizedAssignedShopIds)) {
      return res.status(403).json({
        success: false,
        message: 'Forbidden: you can only create users within your assigned shops',
      });
    }

    // password_hash field triggers the pre-save bcrypt hook
    const user = await User.create({
      name,
      email,
      phone_code,
      phone_num,
      password_hash: password,
      role_id,
      device_id,
      shop_id: primaryShopId,
      assigned_shop_ids: normalizedAssignedShopIds,
      must_change_password: true,
    });

    const populated = await user.populate([
      { path: 'role_id', select: 'role_name permissions' },
      { path: 'shop_id', select: 'name' },
      { path: 'assigned_shop_ids', select: 'name' },
    ]);
    res.status(201).json({ success: true, data: populated });
  } catch (err) {
    res.status(500).json({ success: false, message: err.message });
  }
};

// @route  PUT /api/users/:id
// @access Admin
const updateUser = async (req, res) => {
  try {
    const {
      name,
      email,
      phone_code,
      phone_num,
      role_id,
      device_id,
      shop_id,
      assigned_shop_ids,
    } = req.body;
    const shouldUpdateShops = shop_id !== undefined || assigned_shop_ids !== undefined;
    const existingUser = await User.findById(req.params.id).select('shop_id assigned_shop_ids');
    if (!existingUser) return res.status(404).json({ success: false, message: 'User not found' });
    if (!isUserInShopScope(req.shopScope, existingUser)) {
      return res.status(403).json({
        success: false,
        message: 'Forbidden: user is outside your assigned shops',
      });
    }

    const normalizedAssignedShopIds = shouldUpdateShops
      ? normalizeAssignedShopIds(assigned_shop_ids, shop_id)
      : undefined;
    const primaryShopId = shouldUpdateShops
      ? (shop_id || normalizedAssignedShopIds[0] || null)
      : undefined;

    const updateData = {
      name,
      email,
      phone_code,
      phone_num,
      role_id,
      device_id,
    };
    if (shouldUpdateShops) {
      if (!isRequestedShopSetAllowed(req.shopScope, normalizedAssignedShopIds)) {
        return res.status(403).json({
          success: false,
          message: 'Forbidden: you can only assign users to your allowed shops',
        });
      }
      updateData.shop_id = primaryShopId;
      updateData.assigned_shop_ids = normalizedAssignedShopIds;
    }
    Object.keys(updateData).forEach((key) => {
      if (updateData[key] === undefined) delete updateData[key];
    });

    const user = await User.findByIdAndUpdate(
      req.params.id,
      updateData,
      { new: true, runValidators: true }
    )
      .populate('role_id', 'role_name permissions')
      .populate('shop_id', 'name')
      .populate('assigned_shop_ids', 'name');

    if (!user) return res.status(404).json({ success: false, message: 'User not found' });
    res.json({ success: true, data: user });
  } catch (err) {
    res.status(500).json({ success: false, message: err.message });
  }
};

// @route  DELETE /api/users/:id — soft delete
// @access Admin
const deleteUser = async (req, res) => {
  try {
    const existingUser = await User.findById(req.params.id).select('shop_id assigned_shop_ids');
    if (!existingUser) return res.status(404).json({ success: false, message: 'User not found' });
    if (!isUserInShopScope(req.shopScope, existingUser)) {
      return res.status(403).json({
        success: false,
        message: 'Forbidden: user is outside your assigned shops',
      });
    }

    const user = await User.findByIdAndUpdate(
      req.params.id,
      { is_active: false },
      { new: true }
    );
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });
    res.json({ success: true, message: 'User deactivated successfully' });
  } catch (err) {
    res.status(500).json({ success: false, message: err.message });
  }
};

// @route  PUT /api/users/me/password
// @access Self (JWT required)
const updatePassword = async (req, res) => {
  try {
    const { currentPassword, newPassword } = req.body;

    if (!currentPassword || !newPassword) {
      return res.status(400).json({ success: false, message: 'Both currentPassword and newPassword are required' });
    }
    if (newPassword.length < 8) {
      return res.status(400).json({ success: false, message: 'New password must be at least 8 characters' });
    }

    const user = await User.findById(req.user._id).select('+password_hash');
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });

    const match = await user.matchPassword(currentPassword);
    if (!match) {
      return res.status(401).json({ success: false, message: 'Current password is incorrect' });
    }

    user.password_hash = newPassword; // bcrypt pre-save hook re-hashes
    user.must_change_password = false;
    await user.save();

    res.json({ success: true, message: 'Password updated successfully' });
  } catch (err) {
    res.status(500).json({ success: false, message: err.message });
  }
};

module.exports = {
  getMe,
  getAssignedShopStaffSummary,
  getUsers,
  getUser,
  createUser,
  updateUser,
  deleteUser,
  updatePassword,
};

const jwt = require('jsonwebtoken');
const User = require('../models/User');

const protect = async (req, res, next) => {
  let token;

  if (
    req.headers.authorization &&
    req.headers.authorization.startsWith('Bearer ')
  ) {
    token = req.headers.authorization.split(' ')[1];
  }

  if (!token) {
    return res.status(401).json({ success: false, message: 'Not authorized, no token' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = await User.findById(decoded.id)
      .select('-password_hash')
      .populate('role_id');

    if (!req.user || !req.user.is_active) {
      return res.status(401).json({ success: false, message: 'User not found or deactivated' });
    }

    next();
  } catch (err) {
    return res.status(401).json({ success: false, message: 'Token invalid or expired' });
  }
};

module.exports = { protect };

const jwt = require('jsonwebtoken');
const User = require('../models/User');
const { buildShopScope } = require('./shopScopeMiddleware');

const protect = async (req, res, next) => {
  let token;

  if (
    req.headers.authorization &&
    req.headers.authorization.startsWith('Bearer ')
  ) {
    token = req.headers.authorization.split(' ')[1];
  }

  if (!token) {
    return res.status(401).json({ success: false, message: 'Not authorized, no token' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = await User.findById(decoded.id)
      .select('-password_hash')
      .populate('role_id');

    if (!req.user || !req.user.is_active) {
      return res.status(401).json({ success: false, message: 'User not found or deactivated' });
    }

    req.shopScope = buildShopScope(req.user);

    next();
  } catch (err) {
    return res.status(401).json({ success: false, message: 'Token invalid or expired' });
  }
};

module.exports = { protect };

const rateLimit = require('express-rate-limit');

const toPositiveInt = (value, fallback) => {
  const parsed = Number.parseInt(value, 10);
  return Number.isInteger(parsed) && parsed > 0 ? parsed : fallback;
};

const windowMinutes = toPositiveInt(process.env.LOGIN_RATE_LIMIT_WINDOW_MINUTES, 15);
const maxAttempts = toPositiveInt(process.env.LOGIN_RATE_LIMIT_MAX_ATTEMPTS, 5);

const loginRateLimiter = rateLimit({
  windowMs: windowMinutes * 60 * 1000,
  max: maxAttempts,
  standardHeaders: true,
  legacyHeaders: false,
  message: {
    success: false,
    message: 'Too many login attempts. Please try again later.',
  },
});

module.exports = { loginRateLimiter };

const unique = (ids) => [...new Set(ids)];

const toId = (value) => {
  if (!value) return null;
  if (typeof value === 'string') return value;
  if (value._id) return value._id.toString();
  return value.toString();
};

const resolveAllowedShopIds = (user) => {
  const assigned = Array.isArray(user?.assigned_shop_ids)
    ? user.assigned_shop_ids.map(toId).filter(Boolean)
    : [];
  const primary = toId(user?.shop_id);
  return unique(primary ? [...assigned, primary] : assigned);
};

const canAccessAllShops = (user) => {
  const permissions = user?.role_id?.permissions || {};
  return Boolean(permissions.can_manage_shops || permissions.can_manage_roles);
};

const buildShopScope = (user) => ({
  all: canAccessAllShops(user),
  ids: resolveAllowedShopIds(user),
});

const isShopAllowed = (shopScope, shopId) => {
  if (!shopId) return false;
  if (shopScope?.all) return true;
  const id = toId(shopId);
  return Boolean(id && shopScope?.ids?.includes(id));
};

module.exports = {
  resolveAllowedShopIds,
  canAccessAllShops,
  buildShopScope,
  isShopAllowed,
};

const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');

const userSchema = new mongoose.Schema(
  {
    name: {
      type: String,
      required: [true, 'Name is required'],
      trim: true,
    },
    email: {
      type: String,
      required: [true, 'Email is required'],
      unique: true,
      lowercase: true,
      trim: true,
    },
    phone_code: {
      type: String,
      trim: true, // e.g. "+44"
    },
    phone_num: {
      type: String,
      trim: true,
    },
    password_hash: {
      type: String,
      required: true,
      select: false, // never returned in queries by default
    },
    role_id: {
      type: mongoose.Schema.Types.ObjectId,
      ref: 'Role',
      required: [true, 'Role is required'],
    },
    device_id: {
      type: String,
      trim: true,
      default: null,
    },
    shop_id: {
      type: mongoose.Schema.Types.ObjectId,
      ref: 'Shop',
      default: null,
    },
    is_active: {
      type: Boolean,
      default: true,
    },
    must_change_password: {
      type: Boolean,
      default: true, // Admin-created users must change on first login
    },
  },
  { timestamps: true }
);

// Hash password before saving
// Note: Mongoose v7+ async pre hooks — do NOT call next(), just return
userSchema.pre('save', async function () {
  if (!this.isModified('password_hash')) return;
  const salt = await bcrypt.genSalt(12);
  this.password_hash = await bcrypt.hash(this.password_hash, salt);
});

// Compare plain password with stored hash
userSchema.methods.matchPassword = async function (enteredPassword) {
  return await bcrypt.compare(enteredPassword, this.password_hash);
};

module.exports = mongoose.model('User', userSchema);

