/** * @swagger * /api/users/assigned-shops/staff-summary: * get: * summary: Assigned-shop staff summary (Sub-Manager dashboard) * tags: [Users] * description: Returns active users grouped by assigned shops within the caller's shop scope. * parameters: * - in: query * name: shop_id * schema: * type: string * description: Optional single-shop filter within your allowed shop scope * responses: * 200: * description: Staff summary grouped by shop * content: * application/json: * schema: * $ref: '#/components/schemas/AssignedShopStaffSummaryResponse' * 403: * description: Forbidden (shop outside assigned scope) */ router.get('/assigned-shops/staff-summary', protect, requirePermission('can_manual_punch'), getAssignedShopStaffSummary);
/** * @swagger * /api/users: * get: * summary: List all active users * tags: [Users] * responses: * 200: * description: List of users * post: * summary: Create a new user (Admin only) * tags: [Users] * requestBody: * required: true * content: * application/json: * schema: * $ref: '#/components/schemas/CreateUserRequest' * responses: * 201: * description: User created * 400: * description: Email already in use */ router.get('/', protect, requirePermission('can_view_all_staff'), getUsers); router.post('/', protect, requirePermission('can_create_users'), createUser);
/** * @swagger * /api/users/{id}: * get: * summary: Get user by ID * tags: [Users] * parameters: * - in: path * name: id * required: true * schema: * type: string * responses: * 200: * description: User data * 404: * description: Not found * put: * summary: Update user details * tags: [Users] * parameters: * - in: path * name: id * required: true * schema: * type: string * requestBody: * content: * application/json: * schema: * $ref: '#/components/schemas/CreateUserRequest' * responses: * 200: * description: Updated * delete: * summary: Soft-delete (deactivate) a user * tags: [Users] * parameters: * - in: path * name: id * required: true * schema: * type: string * responses: * 200: * description: User deactivated */ router.get('/:id', protect, requirePermission('can_view_all_staff'), getUser); router.put('/:id', protect, requirePermission('can_create_users'), updateUser); router.delete('/:id', protect, requirePermission('can_create_users'), deleteUser);
module.exports = router;
